import{_ as e,o as a,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"F16: 大股東成本與籌碼結構審計 - 財務審計專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3163_波若威/20260502/F16_大股東成本與籌碼結構審計.md","filePath":"審計報告庫/財務審計/3163_波若威/20260502/F16_大股東成本與籌碼結構審計.md"}'),n={name:"審計報告庫/財務審計/3163_波若威/20260502/F16_大股東成本與籌碼結構審計.md"};function i(o,t,s,d,h,c){return a(),r("div",null,[...t[0]||(t[0]=[l('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f16-大股東成本與籌碼結構審計-財務審計專家-審計報告" tabindex="-1">F16: 大股東成本與籌碼結構審計 - 財務審計專家 審計報告 <a class="header-anchor" href="#f16-大股東成本與籌碼結構審計-財務審計專家-審計報告" aria-label="Permalink to &quot;F16: 大股東成本與籌碼結構審計 - 財務審計專家 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>董監事與大股東持股佔比與增減趨勢為何？董監持股質押比例是否過高？大股東的長期持股成本估值為何？</p><h2 id="🎯-專家直斷-76-字" tabindex="-1">🎯 專家直斷（76 字） <a class="header-anchor" href="#🎯-專家直斷-76-字" aria-label="Permalink to &quot;🎯 專家直斷（76 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：波若威董監持股約 10%、全員零質押——極度安全無斷頭風險。千張大戶在 2025 年從 7 人 15.8% 增至 12 人 27.2%（顯著增持），籌碼集中度持續提升，顯示法人與內部人對長期發展具信心。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：根據截至 2025 年最新公開數據</li></ul><h2 id="📊-診斷評級-115-字" tabindex="-1">📊 診斷評級（115 字） <a class="header-anchor" href="#📊-診斷評級-115-字" aria-label="Permalink to &quot;📊 診斷評級（115 字）&quot;">​</a></h2><p>主要股東結構：國發基金 3.77%（第一大股東）、陳有諒 2.64%、鄭萬來（董事長）2.20%，全體董監事持股約 10%。質押比例為零——無任何董監事將持股設質，完全無平倉風險。籌碼分佈（2025 年底）：千張大戶 12 人（27.2%），400 張以上大戶合計約 30%。千張大戶人數從年初 7 人成長至年底 12 人（+71%），持股佔比從 15.8% 升至 27.2%（+11.4pp），顯示大戶顯著增持。散戶（1-999 股）人數 26,258 人（僅佔 1.2%），籌碼高度集中在專業投資人手中。</p><h2 id="🔍-答詢詳解-328-字" tabindex="-1">🔍 答詢詳解（328 字） <a class="header-anchor" href="#🔍-答詢詳解-328-字" aria-label="Permalink to &quot;🔍 答詢詳解（328 字）&quot;">​</a></h2><h3 id="一、董監持股-利益綑綁度中等但無財務壓力" tabindex="-1">一、董監持股：利益綑綁度中等但無財務壓力 <a class="header-anchor" href="#一、董監持股-利益綑綁度中等但無財務壓力" aria-label="Permalink to &quot;一、董監持股：利益綑綁度中等但無財務壓力&quot;">​</a></h3><p>董監事持股總計約 10%，對比一般上市櫃公司平均水平（15-20%）略低，但考慮國發基金（政府機構）為最大股東 3.77%，整體治理結構可接受。零質押比例意味著董監事無融資買股的財務壓力，不會因股價波動面臨斷頭風險，也不存在被迫賣股償債的壓力。這是治理面的重要正面訊號。</p><h3 id="二、千張大戶-2025-年顯著增持-籌碼集中的結構性訊號" tabindex="-1">二、千張大戶 2025 年顯著增持：籌碼集中的結構性訊號 <a class="header-anchor" href="#二、千張大戶-2025-年顯著增持-籌碼集中的結構性訊號" aria-label="Permalink to &quot;二、千張大戶 2025 年顯著增持：籌碼集中的結構性訊號&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">時點</th><th style="text-align:center;">千張大戶人數</th><th style="text-align:center;">千張大戶佔比</th></tr></thead><tbody><tr><td style="text-align:center;">2025 年初（1月）</td><td style="text-align:center;">7</td><td style="text-align:center;">15.8%</td></tr><tr><td style="text-align:center;">2025 年中（6月）</td><td style="text-align:center;">7~8</td><td style="text-align:center;">15-17%</td></tr><tr><td style="text-align:center;">2025 Q4（11月底）</td><td style="text-align:center;">12</td><td style="text-align:center;">25.4%</td></tr><tr><td style="text-align:center;">2025 年底（12月）</td><td style="text-align:center;">12</td><td style="text-align:center;">27.2%</td></tr></tbody></table><p>千張大戶在 Q4 顯著增加 5 人（+71%），持股佔比從 15.8% 升至 27.2%（+11.4pp）。此增持集中在 2025 年 11-12 月，可能與 CPO 產品量產在即、法人布局明年成長預期有關。400-600 張級距的大戶人數在同期也從 5-6 人增至 10 人，顯示中實戶同步跟進。</p><h3 id="三、大股東成本估算" tabindex="-1">三、大股東成本估算 <a class="header-anchor" href="#三、大股東成本估算" aria-label="Permalink to &quot;三、大股東成本估算&quot;">​</a></h3><p>以公司近 2 年平均股價約 60-80 元區間，且 2025 年 Q4 大量增持（股價約 65-75 元），推估大股東持股成本約 55-70 元。董事長鄭萬來、陳有諒等創始團隊持股成本極低（從公司成立初期持有），帳面獲利豐厚。</p><h2 id="💡-專家評析-226-字" tabindex="-1">💡 專家評析（226 字） <a class="header-anchor" href="#💡-專家評析-226-字" aria-label="Permalink to &quot;💡 專家評析（226 字）&quot;">​</a></h2><ol><li><p><strong>零質押為治理面重大加分項</strong>：在台股中董監質押率 20-30% 為常態的背景下，波若威全體董監事零質押極為罕見。這代表管理層沒有以股票作為個人融資擔保品的財務壓力，不會為了維持股價或質押維持率而做出損害公司長期利益的短視決策。<strong>此為公司治理面最重要的正面訊號之一。</strong></p></li><li><p><strong>國發基金做為最大股東的雙面性</strong>：國發基金持股 3.77% 作為機構法人股東，可提供外部治理監督。但政府基金通常採被動投資策略，不太參與公司經營，對管理層的制衡力道有限。此外國發基金若配合政策減持，可能對股價造成一次性賣壓。</p></li><li><p><strong>千張大戶 Q4 暴增的解讀：籌碼集中 vs 短線過熱</strong>：Q4 千張大戶驟增反映市場對 2026 年營收跳增的預期，但也可能導致籌碼過於集中。若 2026 年營收不如預期，這些 Q4 進場的大戶可能成為潛在賣壓。</p></li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>計算工具</strong>：數據採集器.py (backer_holding 3163)</li><li><strong>原始數據</strong>：FinMind TaiwanStockShareholdingSpread</li><li><strong>補充資訊</strong>：web_search（Goodinfo 董監持股明細）</li><li><strong>查詢參數</strong>：stock_id=3163, start=2025-01-01, end=2025-12-31</li><li><strong>關鍵核對碼</strong>：千張大戶(人/%) 2025 年初=7人/15.8%→年底=12人/27.2%；董監質押=0%；董監持股~10%；國發基金 3.77%</li></ul>',20)])])}const p=e(n,[["render",i]]);export{g as __pageData,p as default};
